import React, { useState } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';  // Importăm Router, Routes și Route
import Sidebar from './components/Sidebar';
import Zoom from './components/Zoom';  // Importăm componenta Zoom
import './App.css';

const App = () => {
  return (
    <Router>
      <div className="App">
        <Sidebar />

        {/* Definim rutele */}
        <Routes>
          {/* Ruta principală */}
          <Route path="/" element={<div>Welcome to My Shortcuts</div>} />

          {/* Navigare către componenta Zoom */}
          <Route path="/zoom" element={<Zoom />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
